                    new DialogueChoice { text = "[PERSUADE 15] \"Then leak them *properly.* Not one page to one buyer — *all* of them, copied wide, nailed where the city reads. Make the dying *count* for something more than your sister's debt.\"", nextNodeId = "leak", checkAbility = Ability.Charisma, checkDC = 15, failNodeId = "scared" },
                    new DialogueChoice { text = "\"Your sister's debt. Tell me the number. Maybe the leaking and the paying don't have to be the same desperate thing.\"", nextNodeId = "sister", effects = new[] { new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 2 } } },
