                onEnter = new[] { new FlagClause { key = "npc.pol_leaks", op = FlagOp.SetTrue }, new FlagClause { key = "sq.pol_pages", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 4 } },
