            g.nodes.Add(new DialogueNode
            {
                id = "pages", speaker = "Scrivener Pol",
                text = "*(He hesitates — then presses a thick, ink-fresh sheaf into your hands, and the relief of *giving it to someone* nearly buckles him.)* The true ones. Not the spell-pages buyers want — these. *(he taps them.)* What the gods stopped doing and when. Which Reader sealed which truth and the *date* they did it. The Wall's own provenance, copied from the volume they pretend burned. *(his hands won't quite let go, then do.)* I've been *hoarding* these — too scared to sell the *real* dynamite, only the titillating stuff — telling myself I was *saving* them for the right hands. *(he laughs, wet.)* I think I was just saving them for someone who'd carry them somewhere *better* than a buyer's pocket. *(he wipes his eyes, smearing ink.)* Take them where they *do* something, Returned. I copied the truth for two years and never once got to see it *land.* Be the place it lands. That's — that's all a copyist ever wants, really. To have copied something that *mattered* to a hand that *used* it.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.pol_gives_pages", op = FlagOp.SetTrue }, new FlagClause { key = "sq.pol_pages", op = FlagOp.SetTrue }, new FlagClause { key = "act2.wall_provenance_pages", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 3 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "deny", speaker = "Scrivener Pol",
                text = "*(He shakes his head fast, retreating into the safer story.)* Whistleblower — no, no, I'm a *businessman*, I sell *pages*, it's *commerce*, don't — don't make it *grand*, grand things get *hanged.* *(he gathers his sheaf protectively.)* It's the *debt.* It's *always* been the debt. If you want pages, the price is the price. If you want to make me into some — some *hero* — find another copyist. I just want the coin and to not be *noticed.* *(he won't meet your eyes, and you both know the denial is the most frightened thing he's said.)*",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "scared", speaker = "Scrivener Pol",
                text = "*(The plan terrifies him back into his hole.)* Nailed across the *whole Gate* — no, no, that's — that's a *gallows*, that's not a *leak* that's a *confession with my name on it* — *(he's shaking.)* I copy in the *dark*, Returned, one page to one buyer, *small*, *quiet*, *survivable.* What you're describing is *loud*, and loud men *hang.* *(he hunches over his work.)* Buy a page if you want a page. But don't ask me to die *spectacularly* for a truth that'll get nailed over by noon. I haven't the *spine* for the version you're selling. I'm sorry. I'm only as brave as the dark allows.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Scrivener Pol",
                text = "*(Whatever you leave him with, Scrivener Pol bends back over his sealed pages, pen moving in the candlelight — a frightened man copying out the truth long after the coin stopped being the reason, becoming, one trembling letter at a time, the thing Candlekeep most fears and most needs: a hand that won't stop writing down what the library decided no one should read.)*",
            });

            NpcKeepPolDialogue = g;
        }
    }
}
